t.script:
(function () {
    function bindSpecimenCombinationBuilder() {
        var form = document.getElementById("lab_test_request_form");
        var container = document.getElementById("specimen_combo_container");
        var addButton = document.getElementById("btn_add_specimen_combo");
        var payloadInput = document.getElementById("specimen_payload_json");
        var patientIdentifierInput = form ? form.querySelector('input[name="patient_identifier"]') : null;
        var patientNameInput = form ? form.querySelector('input[name="patient_name"]') : null;
        var patientPhoneInput = form ? form.querySelector('input[name="patient_phone"]') : null;
        var physicianDepartmentSelect = document.getElementById("physician_department_id");
        var physicianSelect = document.getElementById("physician_partner_id");
        var patientHint = document.getElementById("patient_lookup_hint");
        if (!form || !container || !addButton || !payloadInput) {
            return;
        }

        function filterPhysiciansByDepartment() {
            if (!physicianDepartmentSelect || !physicianSelect) {
                return;
            }
            var selectedDept = (physicianDepartmentSelect.value || "").trim();
            Array.prototype.forEach.call(physicianSelect.options || [], function (opt, idx) {
                if (idx === 0) {
                    opt.hidden = false;
                    return;
                }
                var deptId = (opt.getAttribute("data-department-id") || "").trim();
                var visible = !selectedDept || (deptId && deptId === selectedDept);
                opt.hidden = !visible;
                if (!visible && opt.selected) {
                    physicianSelect.value = "";
                }
            });
        }

        if (physicianDepartmentSelect) {
            physicianDepartmentSelect.addEventListener("change", filterPhysiciansByDepartment);
            filterPhysiciansByDepartment();
        }

        var serviceOptionsTemplate = document.getElementById("lab_service_options_template");
        var profileOptionsTemplate = document.getElementById("lab_profile_options_template");
        var sampleTypeOptionsTemplate = document.getElementById("lab_sample_type_options_template");
        var serviceOptionsHtml = "";
        var profileOptionsHtml = "";
        var sampleTypeOptionsHtml = (sampleTypeOptionsTemplate || {}).innerHTML || "";

        function buildChecklistOptions(selectNode, inputClass) {
            if (!selectNode) {
                return "";
            }
            var rows = [];
            Array.prototype.forEach.call(selectNode.querySelectorAll("option"), function (opt) {
                var value = opt.value || "";
                var label = (opt.textContent || "").trim();
                rows.push(
                    '<div class="form-check">' +
                    '<label class="form-check-label">' +
                    '<input class="form-check-input ' + inputClass + ' me-2" type="checkbox" value="' + value + '">' +
                    label +
                    "</label>" +
                    "</div>"
                );
            });
            return rows.join("");
        }

        serviceOptionsHtml = buildChecklistOptions(serviceOptionsTemplate, "js-service-check");
        profileOptionsHtml = buildChecklistOptions(profileOptionsTemplate, "js-profile-check");

        function toggleCard(card) {
            var lineType = card.querySelector(".js-combo-line-type");
            var serviceGroup = card.querySelector(".js-combo-service-group");
            var profileGroup = card.querySelector(".js-combo-profile-group");
            var serviceChecks = card.querySelectorAll(".js-service-check");
            var profileChecks = card.querySelectorAll(".js-profile-check");
            var mode = lineType ? (lineType.value || "service") : "service";
            if (mode === "profile") {
                serviceGroup.style.display = "none";
                profileGroup.style.display = "";
                Array.prototype.forEach.call(serviceChecks || [], function (opt) { opt.checked = false; });
            } else {
                serviceGroup.style.display = "";
                profileGroup.style.display = "none";
                Array.prototype.forEach.call(profileChecks || [], function (opt) { opt.checked = false; });
            }
        }

        function addSpecimenRow(card) {
            var specimenContainer = card.querySelector(".js-specimen-list");
            var nextSpecimenIndex = specimenContainer.querySelectorAll(".js-specimen-row").length + 1;
            var comboIndex = parseInt(card.getAttribute("data-combo-index"), 10) || 1;
            var specimenRow = document.createElement("div");
            specimenRow.className = "row g-2 align-items-end mb-2 js-specimen-row";
            specimenRow.innerHTML =
                '<div class="col-md-2"><label class="form-label">Specimen Ref</label><input type="text" class="form-control js-specimen-ref" value="C' + comboIndex + '-SP' + nextSpecimenIndex + '"/></div>' +
                '<div class="col-md-3"><label class="form-label">Specimen Type</label><select class="form-select js-specimen-sample-type">' + sampleTypeOptionsHtml + '</select></div>' +
                '<div class="col-md-5"><label class="form-label">Container Code</label><input type="text" class="form-control js-specimen-barcode" placeholder="Container barcode / code"/></div>' +
                '<div class="col-md-2"><button type="button" class="btn btn-outline-danger btn-sm w-100 js-remove-specimen">Remove</button></div>';
            specimenContainer.appendChild(specimenRow);
            specimenRow.querySelector(".js-remove-specimen").addEventListener("click", function () {
                specimenRow.remove();
            });
        }

        function addCard() {
            var idx = container.querySelectorAll(".js-combo-card").length + 1;
            var wrapper = document.createElement("div");
            wrapper.className = "card mb-2 js-combo-card";
            wrapper.setAttribute("data-combo-index", String(idx));
            wrapper.innerHTML =
                '<div class="card-body" style="background:#dfe8f5;border:1px solid #c2d0e4;border-radius:.5rem;">' +
                '<div class="d-flex justify-content-between align-items-center mb-2">' +
                '<strong>Combination #' + idx + '</strong>' +
                '<button type="button" class="btn btn-link text-danger p-0 js-remove-combo">Remove Combination</button>' +
                '</div>' +
                '<div class="row">' +
                '<div class="col-md-3 mb-2"><label class="form-label">Line Type</label><select class="form-select js-combo-line-type"><option value="service">Service</option><option value="profile">Profile</option></select></div>' +
                '<div class="col-md-9 mb-2 js-combo-service-group"><label class="form-label">Services</label><div class="border rounded bg-white p-2 js-combo-service-list" style="max-height:220px;overflow-y:auto;"></div></div>' +
                '<div class="col-md-9 mb-2 js-combo-profile-group" style="display:none;"><label class="form-label">Profiles</label><div class="border rounded bg-white p-2 js-combo-profile-list" style="max-height:220px;overflow-y:auto;"></div></div>' +
                '<div class="col-md-12 mb-2"><label class="form-label">Combination Note</label><input type="text" class="form-control js-combo-line-note" placeholder="Optional note for this combination"/></div>' +
                '<div class="col-md-12"><div class="border rounded p-2 bg-white">' +
                '<div class="d-flex justify-content-between align-items-center mb-2"><strong>Specimens</strong><button type="button" class="btn btn-outline-secondary btn-sm js-add-specimen-in-combo">Add Specimen</button></div>' +
                '<div class="js-specimen-list"></div>' +
                '</div></div>' +
                '</div></div>';
            container.appendChild(wrapper);
            wrapper.querySelector(".js-combo-service-list").innerHTML = serviceOptionsHtml;
            wrapper.querySelector(".js-combo-profile-list").innerHTML = profileOptionsHtml;
            wrapper.querySelector(".js-combo-line-type").addEventListener("change", function () {
                toggleCard(wrapper);
            });
            wrapper.querySelector(".js-remove-combo").addEventListener("click", function () {
                wrapper.remove();
            });
            wrapper.querySelector(".js-add-specimen-in-combo").addEventListener("click", function () {
                addSpecimenRow(wrapper);
            });
            toggleCard(wrapper);
            addSpecimenRow(wrapper);
        }

        addButton.addEventListener("click", addCard);
        addCard();

        function lookupPatientByIdentifier() {
            if (!patientIdentifierInput) {
                return;
            }
            var identifier = (patientIdentifierInput.value || "").trim();
            if (!identifier) {
                if (patientHint) {
                    patientHint.textContent = "";
                }
                return;
            }
            fetch("/my/lab/patient/lookup?identifier=" + encodeURIComponent(identifier), {method: "GET"})
                .then(function (resp) { return resp.json(); })
                .then(function (data) {
                    if (!data || !data.found) {
                        if (patientHint) {
                            patientHint.textContent = "No historical patient found under current account.";
                        }
                        return;
                    }
                    if (patientNameInput) {
                        patientNameInput.value = data.patient_name || "";
                    }
                    if (patientPhoneInput) {
                        patientPhoneInput.value = data.patient_phone || "";
                    }
                    if (patientHint) {
                        patientHint.textContent = "Historical patient info loaded.";
                    }
                })
                .catch(function () {
                    if (patientHint) {
                        patientHint.textContent = "Patient lookup failed.";
                    }
                });
        }

        if (patientIdentifierInput) {
            patientIdentifierInput.addEventListener("blur", lookupPatientByIdentifier);
        }

        form.addEventListener("submit", function (ev) {
            var cards = container.querySelectorAll(".js-combo-card");
            var payload = [];
            cards.forEach(function (card) {
                var lineType = (card.querySelector(".js-combo-line-type").value || "service").trim();
                var lineNote = (card.querySelector(".js-combo-line-note").value || "").trim();
                var selectedServices = Array.from(card.querySelectorAll(".js-service-check:checked") || []).map(function (o) { return o.value; });
                var selectedProfiles = Array.from(card.querySelectorAll(".js-profile-check:checked") || []).map(function (o) { return o.value; });
                if (lineType === "service" && selectedServices.length === 0) {
                    return;
                }
                if (lineType === "profile" && selectedProfiles.length === 0) {
                    return;
                }
                var specimenRows = card.querySelectorAll(".js-specimen-row");
                specimenRows.forEach(function (row) {
                    var specimenRef = (row.querySelector(".js-specimen-ref").value || "").trim() || "SP1";
                    var specimenBarcode = (row.querySelector(".js-specimen-barcode").value || "").trim();
                    var specimenSampleType = (row.querySelector(".js-specimen-sample-type").value || "").trim();
                    payload.push({
                        specimen_ref: specimenRef,
                        specimen_barcode: specimenBarcode,
                        specimen_sample_type: specimenSampleType,
                        line_type: lineType,
                        service_ids: selectedServices,
                        profile_ids: selectedProfiles,
                        line_note: lineNote
                    });
                });
            });
            if (!payload.length) {
                ev.preventDefault();
                window.alert("Please add at least one specimen with selected tests.");
                return;
            }
            payloadInput.value = JSON.stringify(payload);
        });
    }
    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", bindSpecimenCombinationBuilder);
    } else {
        bindSpecimenCombinationBuilder();
    }
})();
